@namespace sv_154c95bcf4ac4661b24180cbdcee2d9b.Components.JobApplication

<nav aria-label="Application progress" class="step-indicator mb-4">
    <ol class="steps">
        @for (int i = 0; i < _stepNames.Length; i++)
        {
            var step = i + 1;
            var isActive = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            <li class="step-item @(isActive ? "active" : "") @(isCompleted ? "completed" : "") @(!isActive && !isCompleted ? "future" : "")"
                @onclick="() => HandleClick(step)"
                role="@(isCompleted ? "button" : "listitem")">
                <div class="step-circle">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <div class="step-label">@_stepNames[i]</div>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] _stepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator .steps {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    position: relative;
}

.step-indicator .steps::before {
    content: '';
    position: absolute;
    top: 18px;
    left: 10%;
    right: 10%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    z-index: 1;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    margin-bottom: 0.5rem;
    transition: all 0.2s;
}

.step-item.active .step-circle {
    background: #0d6efd;
    color: #fff;
    box-shadow: 0 0 0 4px rgba(13, 110, 253, 0.2);
}

.step-item.completed .step-circle {
    background: #198754;
    color: #fff;
    cursor: pointer;
}

.step-item.future .step-circle {
    background: #e9ecef;
    color: #6c757d;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    color: #6c757d;
    white-space: nowrap;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
    cursor: pointer;
}

@namespace sv_154c95bcf4ac4661b24180cbdcee2d9b.Components.JobApplication
@using sv_154c95bcf4ac4661b24180cbdcee2d9b.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-start">
            <h6 class="card-title">Reference @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3 mt-1">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input class="form-control" @bind="Reference.Name" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input class="form-control" @bind="Reference.Relationship" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="Reference.Email" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="Reference.Phone" @bind:event="oninput" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

