@namespace sv_154c95bcf4ac4661b24180cbdcee2d9b.Components.JobApplication
@using sv_154c95bcf4ac4661b24180cbdcee2d9b.Models
@using sv_154c95bcf4ac4661b24180cbdcee2d9b.Services
@inject IApplicationService ApplicationService

<div class="card">
    <div class="card-header"><h5 class="mb-0">Personal Information</h5></div>
    <div class="card-body">
        @if (errors.Count > 0)
        {
            <div class="alert alert-danger">
                <ul class="mb-0">
                    @foreach (var error in errors)
                    {
                        <li>@error</li>
                    }
                </ul>
            </div>
        }

        <div class="row g-3">
