@namespace sv_154c95bcf4ac4661b24180cbdcee2d9b.Components.JobApplication
@using sv_154c95bcf4ac4661b24180cbdcee2d9b.Models

<div class="card">
    <div class="card-header"><h5 class="mb-0">Work History</h5></div>
    <div class="card-body">
        @if (errors.Count > 0)
        {
            <div class="alert alert-danger">
                <ul class="mb-0">
                    @foreach (var error in errors)
                    {
                        <li>@error</li>
                    }
                </ul>
            </div>
        }

        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            <WorkEntryEditor Entry="Entries[index]"
                             Index="index + 1"
                             ShowRemove="Entries.Count > 1"
                             OnRemove="() => RemoveEntry(index)" />
        }

        <button type="button" class="btn btn-outline-secondary" @onclick="AddEntry">
            + Add Another Position
        </button>

        <div class="d-flex justify-content-between mt-4">
            <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> errors = new();

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var e = Entries[i];
            if (string.IsNullOrWhiteSpace(e.Company))
                errors.Add($"Position {i + 1}: Company name is required.");
            if (string.IsNullOrWhiteSpace(e.Title))
                errors.Add($"Position {i + 1}: Job title is required.");
            if (e.StartDate is null)
                errors.Add($"Position {i + 1}: Start date is required.");
        }

        if (errors.Count > 0) return;

        await OnNext.InvokeAsync();
    }
}

