@namespace sv_154c95bcf4ac4661b24180cbdcee2d9b.Components.JobApplication

<div class="card">
    <div class="card-header"><h5 class="mb-0">Cover Letter</h5></div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(error))
        {
            <div class="alert alert-danger">@error</div>
        }

        <div class="mb-3">
            <label class="form-label">Write your cover letter</label>
            <textarea class="form-control" rows="10"
                      @bind="CoverLetter"
                      @bind:event="oninput"
                      @bind:after="NotifyChanged"
                      maxlength="@MaxLength"></textarea>
            <div class="form-text text-end">
                @(CoverLetter?.Length ?? 0) / @MaxLength characters
            </div>
        </div>

        <div class="d-flex justify-content-between mt-4">
            <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? error;

    private async Task NotifyChanged() => await CoverLetterChanged.InvokeAsync(CoverLetter);

    private async Task HandleNext()
    {
        error = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            error = "A cover letter is required.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

