@namespace sv_154c95bcf4ac4661b24180cbdcee2d9b.Components.JobApplication
@using sv_154c95bcf4ac4661b24180cbdcee2d9b.Models

<div class="card">
    <div class="card-header"><h5 class="mb-0">Review Your Application</h5></div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(submitError))
        {
            <div class="alert alert-danger">@submitError</div>
        }

        @* Personal Info *@
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h6>Personal Information</h6>
                <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(1)'>Edit</button>
            </div>
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@Personal.Address</dd>
            </dl>
        </div>
        <hr />

        @* Work History *@
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h6>Work History</h6>
                <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(2)'>Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 ps-3 border-start">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                    <small class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy")
                        – @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
        <hr />

        @* References *@
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h6>References</h6>
                <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(3)'>Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="mb-2 ps-3 border-start">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <small class="text-muted">@r.Email · @r.Phone</small>
                </div>
            }
        </div>
        <hr />

        @* Cover Letter *@
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h6>Cover Letter</h6>
                <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(4)'>Edit</button>
            </div>
            <div class="p-3 bg-light rounded" style="white-space: pre-wrap;">@CoverLetter</div>
        </div>

        <div class="d-flex justify-content-between mt-4">
            <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    <text>Submitting…</text>
                }
                else
                {
                    <text>Submit Application</text>
                }
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private string? submitError;

    private async Task HandleSubmit()
    {
        submitError = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
    }
}

