@page "/apply"
@rendermode InteractiveServer
@using sv_154c95bcf4ac4661b24180cbdcee2d9b.Models
@using sv_154c95bcf4ac4661b24180cbdcee2d9b.Services
@using sv_154c95bcf4ac4661b24180cbdcee2d9b.Components.JobApplication
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h1 class="mb-4">Job Application</h1>

    @if (submittedId is not null)
    {
        <div class="card border-success">
            <div class="card-body text-center py-5">
                <div class="mb-3" style="font-size: 3rem;">✅</div>
                <h3 class="text-success">Application Submitted!</h3>
                <p class="lead">Your application ID is <strong>#@submittedId</strong></p>
                <p class="text-muted">We'll be in touch soon. Thank you for applying!</p>
            </div>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep"
                       CompletedSteps="completedSteps"
                       OnStepClicked="GoToStep" />

        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="personalInfo" OnNext="CompleteCurrentAndAdvance" />
                break;
            case 2:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="CompleteCurrentAndAdvance"
                                 OnBack="GoBack" />
                break;
            case 3:
                <ReferencesStep References="references"
                                OnNext="CompleteCurrentAndAdvance"
                                OnBack="GoBack" />
                break;
            case 4:
                <CoverLetterStep @bind-CoverLetter="coverLetter"
                                 OnNext="CompleteCurrentAndAdvance"
                                 OnBack="GoBack" />
                break;
            case 5:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            IsSubmitting="isSubmitting"
                            OnEditSection="GoToStep"
                            OnBack="GoBack"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new() };
    private List<ReferenceModel> references = new() { new() };
    private string coverLetter = "";

    private bool isSubmitting;
    private int? submittedId;

    private void CompleteCurrentAndAdvance()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private void GoBack()
    {
        if (currentStep > 1)
            currentStep--;
    }

    private async Task SubmitApplication()
    {
        isSubmitting = true;
        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter);

            submittedId = await ApplicationService.SubmitApplicationAsync(application);
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

